const http = require('http');
const fs = require('fs');
const path = require('path');
const root = process.argv[2];
const port = 8899;
const types = {'.html':'text/html','.js':'text/javascript','.css':'text/css','.png':'image/png','.ico':'image/x-icon','.json':'application/json','.svg':'image/svg+xml','.ttf':'font/ttf','.woff':'font/woff','.woff2':'font/woff2'};
http.createServer((req,res)=>{
  let p = decodeURIComponent(req.url.split('?')[0]);
  let fp = path.join(root, p);
  if (!fs.existsSync(fp) || fs.statSync(fp).isDirectory()) {
    // SPA fallback
    const direct = path.join(root, p + '.html');
    fp = fs.existsSync(direct) ? direct : path.join(root, 'index.html');
  }
  fs.readFile(fp,(e,data)=>{
    if(e){res.writeHead(404);res.end('nf');return;}
    res.writeHead(200,{'Content-Type':types[path.extname(fp)]||'application/octet-stream'});
    res.end(data);
  });
}).listen(port,()=>console.log('spa on '+port));
